diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 7bff13d59528..da8161bd5303 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -1850,6 +1850,31 @@ static Value *simplifyAndOrOfFCmps(const SimplifyQuery &Q, FCmpInst *LHS,
                  : ConstantInt::getBool(LHS->getType(), !IsAnd);
   }

+  // Handle same predicate comparisons with same variable and constants:
+  // (fcmp olt X, C1) | (fcmp olt X, C2) --> fcmp olt X, max(C1, C2)
+  // (fcmp olt X, C1) & (fcmp olt X, C2) --> fcmp olt X, min(C1, C2)
+  // (fcmp ogt X, C1) | (fcmp ogt X, C2) --> fcmp ogt X, min(C1, C2)
+  // (fcmp ogt X, C1) & (fcmp ogt X, C2) --> fcmp ogt X, max(C1, C2)
+  if (LHS0 == RHS0 && PredL == PredR) {
+    const APFloat *C0, *C1;
+    if (match(LHS1, m_APFloat(C0)) && match(RHS1, m_APFloat(C1))) {
+      // For ordered less than: larger constant means larger range
+      if (PredL == FCmpInst::FCMP_OLT) {
+        if (C0->compare(*C1) == APFloat::cmpLessThan)
+          return IsAnd ? LHS : RHS;  // C0 < C1: and -> C0, or -> C1
+        if (C0->compare(*C1) == APFloat::cmpGreaterThan)
+          return IsAnd ? RHS : LHS;  // C0 > C1: and -> C1, or -> C0
+      }
+      // For ordered greater than: smaller constant means larger range
+      if (PredL == FCmpInst::FCMP_OGT) {
+        if (C0->compare(*C1) == APFloat::cmpGreaterThan)
+          return IsAnd ? LHS : RHS;  // C0 > C1: and -> C0, or -> C1
+        if (C0->compare(*C1) == APFloat::cmpLessThan)
+          return IsAnd ? RHS : LHS;  // C0 < C1: and -> C1, or -> C0
+      }
+    }
+  }
+
   return nullptr;
 }

